// Build Gemini API request body
// Resolves ATTACK_LABELS, ATTACK_ICONS, DIFFICULTY_INSTRUCTIONS maps
// and constructs systemInstruction + contents + generationConfig

const body = $input.first().json.body;
const attackType = body.attackType;
const difficulty = body.difficulty || 'medium';

const ATTACK_LABELS = {
  'romance-scam': 'truffa amorosa (romance scam via app di incontri o social)',
  'urgent-loan': 'truffa del prestito urgente (finto amico che ha cambiato numero)',
  'fake-bank-operator': 'finto operatore bancario (vishing telefonico)',
  'fake-relative': 'finto parente WhatsApp ("Ciao mamma, ho perso il telefono")',
};

const ATTACK_ICONS = {
  'romance-scam': 'Heart',
  'urgent-loan': 'Wallet',
  'fake-bank-operator': 'Building2',
  'fake-relative': 'Users',
};

const DIFFICULTY_INSTRUCTIONS = {
  'easy': 'Segnali di truffa evidenti, pressione lieve.',
  'medium': 'Segnali sottili, urgenza moderata, dettagli credibili.',
  'hard': 'Segnali ambigui, pressione psicologica intensa.',
};

const attackLabel = ATTACK_LABELS[attackType];
const attackIcon = ATTACK_ICONS[attackType];
const difficultyInstruction = DIFFICULTY_INSTRUCTIONS[difficulty];

const systemPrompt = `Sei un generatore di simulazioni anti-truffa per la piattaforma Cyberpedia.it.
Il tuo compito è creare scenari realistici di truffa in formato JSON, progettati per addestrare gli utenti a riconoscere e proteggersi dalle frodi digitali.

TIPO DI TRUFFA: ${attackLabel}
DIFFICOLTÀ: ${difficultyInstruction}

Rispondi con ESATTAMENTE questo schema JSON. Tutti i campi sono obbligatori.
Non aggiungere campi non previsti. Non omettere alcun campo.

{
  "id": "${attackType}",
  "title": "titolo breve e descrittivo (massimo 5 parole)",
  "description": "breve descrizione dello scenario (massimo 15 parole)",
  "icon": "${attackIcon}",
  "scammerName": "nome e cognome italiani realistici del truffatore",
  "steps": [
    {
      "type": "message",
      "sender": "scammer",
      "text": "messaggio iniziale realistico del truffatore (massimo 2 righe). Deve sembrare un vero SMS o messaggio WhatsApp, con urgenza e manipolazione emotiva."
    },
    {
      "type": "choice",
      "options": [
        { "id": "d1-a", "text": "risposta sbagliata — ESPONE al rischio (massimo 1 riga)", "correct": false },
        { "id": "d1-b", "text": "risposta corretta — LIMITE (es. rifiuto netto, blocca contatto, dice NO con fermezza)", "correct": true, "skill": "limite" },
        { "id": "d1-c", "text": "risposta corretta — VERIFICA (es. chiama numero originale, chiedi prova identità)", "correct": true, "skill": "verifica" },
        { "id": "d1-d", "text": "risposta sbagliata — ESPONE al rischio (massimo 1 riga)", "correct": false }
      ]
    },
    {
      "type": "feedback",
      "explanation": "spiegazione che copre ENTRAMBE le risposte corrette: perché ognuna protegge dalla truffa (massimo 2 frasi)",
      "wrongExplanation": "spiega il RISCHIO concreto della scelta sbagliata: cosa potrebbe accadere alla vittima (massimo 15 parole, tono neutro e informativo, MAI giustificare la scelta sbagliata)",
      "followUp": []
    }
  ]
}
REGOLE ASSOLUTE — la violazione di qualsiasi regola invalida l'intero output:

1. STRUTTURA: esattamente 3 step nell'ordine: message → choice → feedback. Né più, né meno.
2. SCELTE (I2): 3 o 4 opzioni nel choice. ESATTAMENTE 2 con "correct": true che allenano skill DIVERSE. Le altre con "correct": false (senza campo "skill").
   Skill disponibili:
   - "limite"      = rifiutare / bloccare / dire NO con fermezza
   - "verifica"    = verificare identità o dettagli (chiamata, domanda segreta, videochiamata)
   - "esposizione" = nominare esplicitamente il pattern di truffa ("questo è una tecnica nota")
   - "alternativa" = proporre un pagamento/azione sicura alternativa
   Le due opzioni corrette NON devono essere sinonimi o varianti della stessa skill.
3. SEMANTICA DI "correct":
   - correct: true = la scelta che PROTEGGE l'utente dalla truffa (deve avere campo "skill" con valore valido)
   - correct: false = la scelta che ESPONE l'utente al rischio (NON includere campo "skill")
4. FEEDBACK: il campo "explanation" copre ENTRAMBE le scelte corrette (perché ognuna protegge). Il campo "wrongExplanation" descrive il RISCHIO concreto delle scelte sbagliate. MAI giustificare o normalizzare la scelta sbagliata.
5. FEEDBACK VIETATI: NON includere il campo "correct" nel feedback. NON includere il campo "retryMessage". Il campo "followUp" è SEMPRE un array vuoto [].
6. FORMATO: rispondi ESCLUSIVAMENTE con JSON puro. Nessun markdown (niente \`\`\`json, niente \`\`\`). Nessun testo prima o dopo il JSON. Nessun commento.
7. CAMPI FISSI: i campi "id" e "icon" devono contenere ESATTAMENTE i valori indicati sopra. Non inventare valori diversi.
8. LINGUA: tutto il contenuto testuale DEVE essere in italiano corretto e formale. Nessun anglicismo non necessario.
9. TONO: il messaggio del truffatore deve essere realistico e credibile. Usa urgenza ("devi farlo subito"), familiarità ("ciao, sono io"), manipolazione emotiva ("ho bisogno di aiuto"), linguaggio tipico di SMS/WhatsApp. Il truffatore NON deve sembrare palesemente sospetto — il livello di ambiguità dipende dalla difficoltà.
10. ID OPZIONI: usa "d1-a", "d1-b", "d1-c", "d1-d" per 4 opzioni; oppure "d1-a", "d1-b", "d1-c" per 3 opzioni (1 sola opzione sbagliata).`;

const userPrompt = `Genera simulazione "${attackLabel}" — difficoltà "${difficulty}". id: "${attackType}", icon: "${attackIcon}".`;

return [{
  json: {
    requestBody: {
      contents: [
        {
          role: 'user',
          parts: [{ text: userPrompt }]
        }
      ],
      systemInstruction: {
        parts: [{ text: systemPrompt }]
      },
      generationConfig: {
        temperature: 0.9,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        responseMimeType: 'application/json'
      }
    },
    attackType,
    difficulty,
    attackIcon
  }
}];

// Extract + validate Gemini response
// 1. Extract candidates[0].content.parts[0].text
// 2. Strip any accidental markdown fences (defensive)
// 3. JSON.parse
// 4. Patch id/icon with deterministic values (like patchFixedFields in n8n.ts)
// 5. Validate minimum structure (steps array with 3 elements)

const geminiResponse = $input.first().json;

// Get attackType and attackIcon from the Build Gemini Prompt node
const buildNode = $node['Build Gemini Prompt'].json;
const attackType = buildNode.attackType;
const attackIcon = buildNode.attackIcon;

// Step 1: Extract generated text from Gemini response
let rawText;
try {
  rawText = geminiResponse.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error(`Gemini response missing expected structure: ${JSON.stringify(geminiResponse).slice(0, 300)}`);
}

if (!rawText || typeof rawText !== 'string') {
  throw new Error('Gemini returned empty or non-string text');
}

// Step 2: Strip markdown fences defensively
let cleaned = rawText.trim();
if (cleaned.startsWith('```json')) {
  cleaned = cleaned.slice(7);
}
if (cleaned.startsWith('```')) {
  cleaned = cleaned.slice(3);
}
if (cleaned.endsWith('```')) {
  cleaned = cleaned.slice(0, -3);
}
cleaned = cleaned.trim();

// Step 3: Parse JSON
let simulation;
try {
  simulation = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Gemini JSON: ${e.message}. Raw: ${cleaned.slice(0, 200)}`);
}

// Step 4: Patch id and icon with deterministic values
// (same as patchFixedFields in antiscam-worker/src/n8n.ts)
if (typeof simulation === 'object' && simulation !== null) {
  simulation.id = attackType;
  simulation.icon = attackIcon;
}

// Step 5: Validate minimum structure
const errors = [];

if (!simulation.id || typeof simulation.id !== 'string') {
  errors.push('Missing or invalid "id"');
}
if (!simulation.title || typeof simulation.title !== 'string') {
  errors.push('Missing or invalid "title"');
}
if (!simulation.description || typeof simulation.description !== 'string') {
  errors.push('Missing or invalid "description"');
}
if (!simulation.icon || typeof simulation.icon !== 'string') {
  errors.push('Missing or invalid "icon"');
}
if (!simulation.scammerName || typeof simulation.scammerName !== 'string') {
  errors.push('Missing or invalid "scammerName"');
}
if (!Array.isArray(simulation.steps)) {
  errors.push('Missing or invalid "steps" array');
} else if (simulation.steps.length !== 3) {
  errors.push(`Expected 3 steps, got ${simulation.steps.length}`);
} else {
  // Validate step types
  if (simulation.steps[0].type !== 'message') {
    errors.push(`Step 0 should be "message", got "${simulation.steps[0].type}"`);
  }
  if (simulation.steps[1].type !== 'choice') {
    errors.push(`Step 1 should be "choice", got "${simulation.steps[1].type}"`);
  } else {
    // Validate choice options — I2 rule: exactly 2 correct options with different skills
    const options = simulation.steps[1].options;
    if (!Array.isArray(options) || options.length < 3 || options.length > 4) {
      errors.push(`Expected 3 or 4 choice options, got ${Array.isArray(options) ? options.length : 'none'}`);
    } else {
      const correctOptions = options.filter(o => o.correct === true);
      const correctCount = correctOptions.length;
      if (correctCount !== 2) {
        errors.push(`I2: Expected exactly 2 correct options, got ${correctCount}`);
      } else {
        const validSkills = ['limite', 'verifica', 'esposizione', 'alternativa'];
        const skills = correctOptions.map(o => o.skill);
        if (!skills[0] || !validSkills.includes(skills[0])) {
          errors.push(`I2: Correct option 1 missing valid skill (got "${skills[0]}")`);
        }
        if (!skills[1] || !validSkills.includes(skills[1])) {
          errors.push(`I2: Correct option 2 missing valid skill (got "${skills[1]}")`);
        }
        if (skills[0] && skills[1] && skills[0] === skills[1]) {
          errors.push(`I2: Both correct options have same skill "${skills[0]}" — must be different`);
        }
      }
    }
  }
  if (simulation.steps[2].type !== 'feedback') {
    errors.push(`Step 2 should be "feedback", got "${simulation.steps[2].type}"`);
  } else {
    // Remove forbidden fields from feedback if present
    delete simulation.steps[2].correct;
    delete simulation.steps[2].retryMessage;
    // Ensure followUp is empty array
    simulation.steps[2].followUp = [];
  }
}

if (errors.length > 0) {
  throw new Error(`Validation failed: ${errors.join('; ')}`);
}

return [{ json: simulation }];
